        if arrival_time < time_window[0]:
            return time_window[0] - arrival_time  # Early arrival penalty
        elif arrival_time > time_window[1]:
            return (arrival_time - time_window[1]) * 10  # Late arrival penalty
        else:
            return 0  # On-time

    scores = []
    for i, customer_pos in enumerate(unvisited_customers):
        time_to_customer = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + time_to_customer
        penalty = time_window_penalty(arrival_time, time_windows[i])
        score = time_to_customer + penalty
        scores.append(score)

    # Collective decision making
    collective_decision_scores = np.array(scores) + 0.1 * np.random.rand(len(scores))

    # Choosing the best option based on the lowest score
    best_node = np.argmin(collective_decision_scores)

    return best_node

